)

func solve(prices []int64, strategy []int64, k int64) int64 {
    n := len(prices)
    if n == 0 {
        return 0
    }

    prefixOriginal := make([]int64, n)
    prefixPrices := make([]int64, n)

    prefixOriginal[0] = strategy[0] * prices[0]
    prefixPrices[0] = prices[0]

    for i := 1; i < n; i++ {
        prefixOriginal[i] = prefixOriginal[i-1] + strategy[i] * prices[i]
        prefixPrices[i] = prefixPrices[i-1] + prices[i]
    }

    originalProfit := prefixOriginal[n-1]
    maxChange := int64(0)
    halfK := k / 2

    for i := 0; i <= n - int(k); i++ {
        end := i + int(k) - 1

        var originalContribution int64
        if i == 0 {
            originalContribution = prefixOriginal[end]
        } else {
            originalContribution = prefixOriginal[end] - prefixOriginal[i-1]
        }

        startSecond := i + halfK
        endSecond := end

        var sumSecond int64
        if startSecond == 0 {
            sumSecond = prefixPrices[endSecond]
        } else {
            sumSecond = prefixPrices[endSecond] - prefixPrices[startSecond-1]
        }

        change := sumSecond - originalContribution
        if change > maxChange {
            maxChange = change
        }
    }

    return originalProfit + int64(math.Max(float64(maxChange), 0))
}
