```javascript
function solve(prices, strategy, k) {
    const n = prices.length;
    if (n === 0) return 0;
    const prefixOriginal = new Array(n).fill(0);
    const prefixPrices = new Array(n).fill(0);
    prefixOriginal[0] = strategy[0] * prices[0];
    prefixPrices[0] = prices[0];
    for (let i = 1; i < n; i++) {
        prefixOriginal[i] = prefixOriginal[i - 1] + strategy[i] * prices[i];
        prefixPrices[i] = prefixPrices[i - 1] + prices[i];
    }
    let originalProfit = prefixOriginal[n - 1];
    let maxChange = 0;
    const halfK = k / 2;
    for (let i = 0; i <= n - k; i++) {
        const end = i + k - 1;
        let original = 0;
        if (i > 0) {
            original = prefixOriginal[end] - prefixOriginal[i - 1];
        } else {
            original = prefixOriginal[end];
        }
        const secondHalfStart = i + halfK;
        const secondHalfEnd = end;
        let sumSecond = 0;
        if (secondHalfStart > 0) {
            sumSecond = prefixPrices[secondHalfEnd] - prefixPrices[secondHalfStart - 1];
        } else {
            sumSecond = prefixPrices[secondHalfEnd];
        }
        const change = sumSecond - original;
        if (change > maxChange) {
            maxChange = change;
        }
    }
    return originalProfit + Math.max(maxChange, 0);
}
